from jinja2 import Environment

class FakeTranslations:
    def gettext(self, s):
        return 'G:' + s
    def ngettext(self, s, p, n):
        return ('NG_S:' if n==1 else 'NG_P:') + (s if n==1 else p)
    def dgettext(self, d, s):
        return f'D[{d}]:{s}'
    def dngettext(self, d, s, p, n):
        return f'DN[{d}]:' + (s if n==1 else p)

